import React, { useState, useEffect, useContext } from 'react';
import { AuthContext } from '../context/AuthContext';
import FoodLogger from '../components/dashboard/FoodLogger';
import NutrientPieChart from '../components/dashboard/NutrientPieChart';
import MealSuggestions from '../components/dashboard/MealSuggestions';
import api from '../api';

const Dashboard = () => {
  const { user } = useContext(AuthContext);
  const [todaysFoods, setTodaysFoods] = useState([]);
  const [nutrientTotals, setNutrientTotals] = useState({
    calories: 0,
    protein: 0,
    carbs: 0,
    fat: 0,
    sugar: 0,
    fiber: 0
  });

  const fetchTodaysFood = async () => {
    try {
      const res = await api.get('/food/today');
      setTodaysFoods(res.data);
    } catch (err) {
      console.error('Error fetching today\'s food:', err);
    }
  };

  useEffect(() => {
    console.log("Dashboard component mounted. Attempting to fetch food..."); // Diagnostic log
    fetchTodaysFood();
  }, []);

  useEffect(() => {
    // Calculate totals whenever the food list changes
    const totals = todaysFoods.reduce((acc, food) => {
      acc.calories += food.calories;
      acc.protein += food.protein;
      acc.carbs += food.carbohydrates;
      acc.fat += food.fat;
      acc.sugar += food.sugar;
      acc.fiber += food.fiber;
      return acc;
    }, { calories: 0, protein: 0, carbs: 0, fat: 0, sugar: 0, fiber: 0 });

    setNutrientTotals(totals);
  }, [todaysFoods]);

  // This function will be passed to the FoodLogger
  const handleFoodLogged = (newFood) => {
    setTodaysFoods([...todaysFoods, newFood]);
  };

  return (
    <div className="container mx-auto p-4 md:p-8">
      <h1 className="text-3xl font-bold text-gray-800 mb-4">
        Welcome, {user && user.name}!
      </h1>
      <p className="text-gray-600 mb-8">
        Log your meals to track your daily nutrient intake and stay on top of your health goals.
      </p>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Left Column: Food Logger and Food List */}
        <div className="lg:col-span-2 space-y-8">
          <div className="bg-white p-6 rounded-lg shadow-md">
            <h2 className="text-2xl font-semibold mb-4 text-gray-700">Log Your Meal</h2>
            <FoodLogger onFoodLogged={handleFoodLogged} />
          </div>

          <div className="bg-white p-6 rounded-lg shadow-md">
            <h2 className="text-2xl font-semibold mb-4 text-gray-700">Today's Logged Foods</h2>
            <div className="overflow-x-auto">
              <table className="min-w-full text-left text-sm font-light">
                <thead className="border-b font-medium dark:border-neutral-500">
                  <tr>
                    <th scope="col" className="px-6 py-4">Food</th>
                    <th scope="col" className="px-6 py-4">Calories</th>
                    <th scope="col" className="px-6 py-4">Protein (g)</th>
                    <th scope="col" className="px-6 py-4">Carbs (g)</th>
                    <th scope="col" className="px-6 py-4">Fat (g)</th>
                  </tr>
                </thead>
                <tbody>
                  {todaysFoods.length > 0 ? (
                    todaysFoods.map((food) => (
                      <tr className="border-b dark:border-neutral-500" key={food._id}>
                        <td className="whitespace-nowrap px-6 py-4 font-medium capitalize">{food.name}</td>
                        <td className="whitespace-nowrap px-6 py-4">{food.calories.toFixed(1)}</td>
                        <td className="whitespace-nowrap px-6 py-4 text-green-600 font-semibold">{food.protein.toFixed(1)}</td>
                        <td className="whitespace-nowrap px-6 py-4">{food.carbohydrates.toFixed(1)}</td>
                        <td className="whitespace-nowrap px-6 py-4">{food.fat.toFixed(1)}</td>
                      </tr>
                    ))
                  ) : (
                    <tr>
                      <td colSpan="5" className="text-center py-4 text-gray-500">No foods logged for today.</td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </div>

        {/* Right Column: Nutrient Chart and Suggestions */}
        <div className="space-y-8">
          <div className="bg-white p-6 rounded-lg shadow-md">
            <h2 className="text-2xl font-semibold mb-4 text-gray-700">Today's Nutrients</h2>
            <NutrientPieChart data={nutrientTotals} />
          </div>
          <div className="bg-white p-6 rounded-lg shadow-md">
            <h2 className="text-2xl font-semibold mb-4 text-gray-700">High-Protein Suggestions</h2>
            <MealSuggestions />
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
